# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

import pyotp
import base64
import qrcode
from PIL import Image

def generate_totp_secret():
    return pyotp.random_base32()

def generate_qr_code(secret, issuer_name, account_name):
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(name=account_name, issuer_name=issuer_name)
    qr = qrcode.QRCode(
        version=1,
        error_correction=qrcode.constants.ERROR_CORRECT_L,
        box_size=10,
        border=4,
    )
    qr.add_data(totp_uri)
    qr.make(fit=True)

    img = qr.make_image(fill_color="black", back_color="white")
    return img

def validate_totp_code(secret, code):
    totp = pyotp.TOTP(secret)
    return totp.verify(code)

# Example usage
if __name__ == "__main__":
    secret = generate_totp_secret()
    print("Generated TOTP Secret:", secret)

    # Generate QR code for the secret
    qr_image = generate_qr_code(secret, issuer_name="MyApp", account_name="user@example.com")
    qr_image.show()

    # Validate a TOTP code
    totp_code = input("Enter TOTP Code: ")
    if validate_totp_code(secret, totp_code):
        print("TOTP code is valid.")
    else:
        print("TOTP code is invalid.")